import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class SpacingAroundColonRuleAnnotationTest {
    private val spacingAroundColonRuleAssertThat = assertThatRule { SpacingAroundColonRule() }

    @Test
    fun `Given annotation use-site targets with spacing before the colon`() {
        val code =
            """
            @file :JvmName("Foo")
            class Example {
                @set :[Inject VisibleForTesting]
                lateinit var collaborator: Collaborator
            }
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            class Example {
                @set:[Inject VisibleForTesting]
                lateinit var collaborator: Collaborator
            }
            """.trimIndent()

        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
